let patched = 0;
let modified = [];
for (const tool of tools) {
    if (enrichment[tool.id]) {
        Object.assign(tool, enrichment[tool.id]);
        patched++;
        modified.push(tool.id);
    }
}
writeFileSync(PATH, JSON.stringify(tools, null, 2));
